USE Library;
GO

IF NOT EXISTS (SELECT 1 FROM EmailTemplates WHERE Purpose = 'Issue Request')
INSERT INTO EmailTemplates (Purpose, Subject, Body) VALUES ('Issue Request', 'Issue Request Received: {{BookName}}', '');

UPDATE EmailTemplates SET Body = '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; border: 1px solid #e2e8f0; border-radius: 12px; overflow: hidden; box-shadow: 0 10px 25px rgba(0,0,0,0.05);"><div style="background-color: #0F172A; padding: 25px 20px; text-align: center; border-bottom: 4px solid #ea580c;"><h2 style="color: #ffffff; margin: 0; font-size: 22px; letter-spacing: 1px;">JINDAL STAINLESS</h2><p style="color: #ea580c; font-size: 11px; margin: 5px 0 0 0; text-transform: uppercase; letter-spacing: 2px; font-weight: bold;">Corporate Library Portal</p></div><div style="padding: 35px 30px; background-color: #ffffff; color: #334155; line-height: 1.7;"><h3 style="color: #0F172A; margin-top: 0; font-size: 18px;">Request Received</h3><p>Hello,</p><p>We have received your request to issue the book <strong style="color: #ea580c;">''{{BookName}}''</strong>. You will be notified once it is approved by the administration.</p><p style="margin-top: 30px;">Best Regards,<br><strong style="color: #0F172A;">Library Admin</strong></p></div><div style="background-color: #f8fafc; padding: 15px; text-align: center; font-size: 12px; color: #94a3b8; border-top: 1px solid #e2e8f0;">&copy; 2026 Jindal Stainless Limited. All rights reserved.</div></div>'
WHERE Purpose = 'Issue Request';

