UPDATE EmailTemplates SET Body = '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; border: 1px solid #e2e8f0; border-radius: 12px; overflow: hidden; box-shadow: 0 10px 25px rgba(0,0,0,0.05);"><div style="background-color: #0F172A; padding: 25px 20px; text-align: center; border-bottom: 4px solid #ea580c;"><h2 style="color: #ffffff; margin: 0; font-size: 22px; letter-spacing: 1px;">JINDAL STAINLESS</h2><p style="color: #ea580c; font-size: 11px; margin: 5px 0 0 0; text-transform: uppercase; letter-spacing: 2px; font-weight: bold;">Corporate Library Portal</p></div><div style="padding: 35px 30px; background-color: #ffffff; color: #334155; line-height: 1.7;"><h3 style="color: #0F172A; margin-top: 0; font-size: 18px;">Login Verification</h3><p>Hello {{EmployeeName}},</p><p>Your one-time password (OTP) for logging into the Library System is:</p><div style="margin: 25px 0; text-align: center;"><span style="display: inline-block; background-color: #f8fafc; border: 2px dashed #cbd5e1; padding: 15px 30px; font-size: 32px; font-weight: bold; letter-spacing: 5px; color: #ea580c; border-radius: 8px;">{{OTP}}</span></div><p style="font-size: 13px; color: #64748b; text-align: center;">This code is valid for 5 minutes.</p><p style="margin-top: 30px;">Best Regards,<br><strong style="color: #0F172A;">Library Admin</strong></p></div><div style="background-color: #f8fafc; padding: 15px; text-align: center; font-size: 12px; color: #94a3b8; border-top: 1px solid #e2e8f0;">&copy; 2026 Jindal Stainless Limited. All rights reserved.</div></div>'
